const source = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const headers = $json.headers || {};
const binary = $binary || {};
const binaryKeys = Object.keys(binary);
const allowedActions = new Set(['authorize', 'search', 'upload', 'collection_status', 'collection_clear', 'feedback']);
const action = String(source.action || $json.query?.action || '').trim().toLowerCase();
if (!allowedActions.has(action)) {
  throw new Error('Unsupported action. Expected authorize, search, upload, collection_status, collection_clear or feedback.');
}
const email = String(source.email || source.userEmail || headers['x-user-email'] || headers['X-User-Email'] || '').trim().toLowerCase();
const parsedLimit = Number(source.limit || source.top_k || 6);
const limit = Number.isFinite(parsedLimit) ? Math.max(1, Math.min(12, Math.round(parsedLimit))) : 6;
const requestStartedMs = Date.now();
const requestedAt = new Date(requestStartedMs).toISOString();
const normalized = {
  action,
  email,
  query: String(source.query || '').trim(),
  limit,
  preset: String(source.preset || 'balanced').trim() || 'balanced',
  requestId: `${$execution.id}-${requestStartedMs}`,
  targetRequestId: String(source.request_id || source.requestId || '').trim(),
  requestedAt,
  requestStartedMs,
  remoteIp: headers['x-forwarded-for'] || headers['x-real-ip'] || null,
  userAgent: headers['user-agent'] || headers['User-Agent'] || null,
  hasFile: binaryKeys.length > 0,
  fileField: null,
  originalFileName: null,
  fileSizeBytes: Number(source.file_size_bytes || source.fileSizeBytes || 0) || 0,
  mimeType: String(source.mime_type || source.mimeType || '').trim(),
  fileSha1: String(source.file_sha1 || source.fileSha1 || '').trim(),
  maxChunkChars: String(source.max_chunk_chars || source.maxChunkChars || '').trim(),
  feedbackValue: String(source.feedback || source.answer_useful || '').trim().toLowerCase(),
  feedbackReason: String(source.feedback_reason || '').trim(),
  feedbackComment: String(source.feedback_comment || '').trim(),
  selectedDoc: String(source.selected_doc || '').trim(),
  selectedCitation: String(source.selected_citation || '').trim(),
  answerText: String(source.answer_text || '').trim(),
  clickedAfterMs: source.clicked_after_ms ?? source.clickedAfterMs ?? null
};
if (binaryKeys.length > 0) {
  const fileField = binary.file ? 'file' : binaryKeys[0];
  normalized.fileField = fileField;
  normalized.originalFileName = binary[fileField]?.fileName || 'document.docx';
  normalized.mimeType = normalized.mimeType || binary[fileField]?.mimeType || '';
  return [{ json: normalized, binary: { file: binary[fileField] } }];
}
return [{ json: normalized }];

const request = $node['Normalize Request']?.json ?? {};
const inputItems = $input.all();
const normalize = (value) => String(value ?? '').trim().toLowerCase();
const truthy = new Set(['1', 'true', 'yes', 'y', 'active', 'enabled', 'allowed', 'ok']);
const falsy = new Set(['0', 'false', 'no', 'n', 'inactive', 'disabled', 'blocked', 'denied']);
const fieldAliases = {
  email: ['email', 'e-mail', 'mail', 'user_email'],
  role: ['role', 'user_role', 'access_role'],
  active: ['active', 'enabled', 'is_active', 'allowed', 'status', 'access'],
  name: ['name', 'full_name', 'user_name'],
};
const bootstrapUsers = {
  'volkovmm@outlook.com': {
    role: 'admin',
    displayName: 'Admin Admin',
  },
};

const buildAuthorized = (baseRequest, role, displayName, authMessage) => ({
  ...baseRequest,
  isAuthorized: true,
  authMessage,
  role,
  displayName,
  canUpload: ['admin', 'editor'].includes(role),
  canManageCollection: role === 'admin'
});

const buildForbidden = (baseRequest, authMessage, role = 'viewer', displayName = '') => ({
  ...baseRequest,
  isAuthorized: false,
  authMessage,
  role,
  displayName,
  canUpload: false,
  canManageCollection: false
});

const findValue = (row, aliases) => {
  const aliasSet = new Set(aliases.map(normalize));
  for (const [key, value] of Object.entries(row || {})) {
    if (aliasSet.has(normalize(key))) {
      return value;
    }
  }
  return '';
};

const bootstrapUser = bootstrapUsers[normalize(request.email)] || null;

if (!request.email) {
  return [{ json: buildForbidden(request, 'Укажите рабочий e-mail.') }];
}

const legacyValues = inputItems.length === 1 && Array.isArray(inputItems[0]?.json?.values) ? inputItems[0].json.values : null;
let rows = [];
let availableKeys = new Set();

if (legacyValues) {
  if (legacyValues.length === 0) {
    if (bootstrapUser) {
      return [{ json: buildAuthorized(request, bootstrapUser.role, bootstrapUser.displayName, 'Доступ подтверждён через bootstrap allowlist.') }];
    }
    return [{ json: buildForbidden(request, 'Лист authorized_users пуст.') }];
  }
  const headers = Array.isArray(legacyValues[0]) ? legacyValues[0].map((header) => String(header ?? '')) : [];
  availableKeys = new Set(headers.map(normalize));
  rows = legacyValues.slice(1).map((row) => Object.fromEntries(headers.map((header, index) => [header, row?.[index] ?? ''])));
} else {
  rows = inputItems.map((item) => item?.json ?? {}).filter((row) => Object.keys(row).length > 0 && !row.error);
  availableKeys = new Set(rows.flatMap((row) => Object.keys(row).map(normalize)));
}

if (inputItems.some((item) => item?.json?.error)) {
  const firstError = inputItems.find((item) => item?.json?.error)?.json?.error;
  const message = typeof firstError === 'string' ? firstError : firstError?.message || 'Не удалось прочитать лист authorized_users.';
  if (bootstrapUser) {
    return [{ json: buildAuthorized(request, bootstrapUser.role, bootstrapUser.displayName, 'Доступ подтверждён через bootstrap allowlist.') }];
  }
  return [{ json: buildForbidden(request, message) }];
}

if (rows.length === 0) {
  if (bootstrapUser) {
    return [{ json: buildAuthorized(request, bootstrapUser.role, bootstrapUser.displayName, 'Доступ подтверждён через bootstrap allowlist.') }];
  }
  return [{ json: buildForbidden(request, 'Лист authorized_users пуст.') }];
}

if (!fieldAliases.email.some((alias) => availableKeys.has(alias))) {
  if (bootstrapUser) {
    return [{ json: buildAuthorized(request, bootstrapUser.role, bootstrapUser.displayName, 'Доступ подтверждён через bootstrap allowlist.') }];
  }
  return [{ json: buildForbidden(request, 'В листе authorized_users нет колонки email.') }];
}

const email = normalize(request.email);
const matchedRow = rows.find((row) => normalize(findValue(row, fieldAliases.email)) === email);

if (!matchedRow) {
  if (bootstrapUser) {
    return [{ json: buildAuthorized(request, bootstrapUser.role, bootstrapUser.displayName, 'Доступ подтверждён через bootstrap allowlist.') }];
  }
  return [{ json: buildForbidden(request, 'Пользователь не найден в списке authorized_users.') }];
}

const activeRaw = normalize(findValue(matchedRow, fieldAliases.active));
const isActive = activeRaw === '' ? true : truthy.has(activeRaw) || !falsy.has(activeRaw);
const rawRole = normalize(findValue(matchedRow, fieldAliases.role) || 'viewer');
const role = ['admin', 'editor', 'viewer'].includes(rawRole) ? rawRole : 'viewer';
const displayName = String(findValue(matchedRow, fieldAliases.name) || '').trim();

if (!isActive) {
  return [{ json: buildForbidden(request, 'Доступ для пользователя отключён.', role, displayName) }];
}

return [{ json: buildAuthorized(request, role, displayName, 'Доступ подтверждён.') }];

const auth = $json;
return [{
  json: {
    ...auth,
    logRow: {
      created_at_utc: auth.requestedAt,
      request_id: auth.requestId,
      action: auth.action,
      email: auth.email || '',
      display_name: auth.displayName || '',
      role: auth.role || 'viewer',
      auth_status: auth.isAuthorized ? 'authorized' : 'forbidden',
      auth_message: auth.authMessage || '',
      can_upload: auth.canUpload ? 'yes' : 'no',
      can_manage_collection: auth.canManageCollection ? 'yes' : 'no',
      remote_ip: auth.remoteIp || '',
      user_agent: auth.userAgent || '',
      execution_id: String($execution.id)
    }
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
return [{
  json: {
    ok: false,
    statusCode: 403,
    error: 'forbidden',
    action: auth.action,
    email: auth.email || null,
    role: auth.role || 'viewer',
    requestId: auth.requestId,
    requestedAt: auth.requestedAt,
    message: auth.authMessage || 'Доступ запрещён.'
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
return [{
  json: {
    ok: true,
    statusCode: 200,
    action: 'authorize',
    email: auth.email,
    role: auth.role,
    requestId: auth.requestId,
    requestedAt: auth.requestedAt,
    displayName: auth.displayName || null,
    permissions: {
      search: true,
      upload: auth.canUpload,
      collection_status: true,
      collection_clear: auth.canManageCollection,
      feedback: true
    },
    message: auth.authMessage
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
if (!auth.query) {
  throw new Error('Search query is required');
}
return [{
  json: {
    query: auth.query,
    top_k: auth.limit,
    generate_answer: true
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
const payload = $json || {};
const hits = Array.isArray(payload.hits) ? payload.hits : Array.isArray(payload.fragments) ? payload.fragments : [];
const answer = String(payload.answer || hits[0]?.raw_text || hits[0]?.text || '').trim();
const fallbackPatterns = [
  /к сожалению/i,
  /не найден[а-я\s]*информац/i,
  /не удалось найти/i,
  /ответ[а-я\s]*не найден/i,
  /в доступных регламентах не найден/i
];
const answerFound = answer !== '' && !fallbackPatterns.some((pattern) => pattern.test(answer.toLowerCase()));
const responseType = hits.length === 0 ? 'zero_results' : answerFound ? 'answer_found' : 'no_answer';
const documentRefs = hits.map((hit) => hit.doc_title || hit.doc_name || hit.source_file || '').filter(Boolean).slice(0, 8).join(' | ');
const citations = hits.map((hit) => hit.citation || hit.heading || '').filter(Boolean).slice(0, 8).join(' | ');
const topChunks = hits.slice(0, 5).map((hit, index) => ({
  rank: hit.rank || index + 1,
  score: hit.score ?? hit.rrf_score ?? null,
  doc_title: hit.doc_title || hit.doc_name || null,
  source_file: hit.source_file || null,
  citation: hit.citation || hit.heading || null,
  chunk_id: hit.id || hit.chunk_id || null,
  document_url: hit.document_url || hit.doc_url || null
}));
const selectedChunksJson = JSON.stringify(topChunks).slice(0, 45000);
const uniqueDocsCount = new Set(hits.map((hit) => hit.doc_title || hit.doc_name || hit.source_file || '').filter(Boolean)).size;
const top1ScoreRaw = hits[0]?.score ?? hits[0]?.rrf_score ?? null;
const top1Score = typeof top1ScoreRaw === 'number' ? top1ScoreRaw.toFixed(6) : top1ScoreRaw == null ? '' : String(top1ScoreRaw);
const zeroResults = hits.length === 0 ? 'yes' : 'no';
const latencyMs = Math.max(0, Date.now() - Number(auth.requestStartedMs || Date.now()));
const retrievalMode = String(payload.retrieval_mode || payload.search_mode || payload.searchMethod || payload.mode || 'unknown');
const generationMode = answerFound ? 'answer' : hits.length === 0 ? 'none' : 'fallback';
const collectionName = String(payload.collection_name || payload.collection || '').trim();
const indexVersion = String(payload.index_version || payload.indexVersion || '').trim();
return [{
  json: {
    response: {
      ...payload,
      answer,
      answerFound,
      answer_found: answerFound,
      responseType,
      response_type: responseType,
      ok: true,
      authorizedEmail: auth.email,
      role: auth.role,
      requestId: auth.requestId,
      requestedAt: auth.requestedAt,
      latencyMs
    },
    logRow: {
      created_at_utc: auth.requestedAt,
      request_id: auth.requestId,
      email: auth.email,
      role: auth.role,
      query_text: auth.query,
      top_k: String(auth.limit),
      preset: auth.preset,
      retrieval_mode: retrievalMode,
      generation_mode: generationMode,
      answer_text: answer,
      found_documents: documentRefs,
      found_citations: citations,
      top_chunks_json: selectedChunksJson,
      hits_count: String(hits.length),
      unique_docs_count: String(uniqueDocsCount),
      top1_score: top1Score,
      zero_results: zeroResults,
      latency_ms: String(latencyMs),
      collection_name: collectionName,
      index_version: indexVersion,
      status: 'success',
      error_message: '',
      feedback: '',
      feedback_at: '',
      execution_id: String($execution.id)
    }
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
return [{
  json: {
    ok: false,
    statusCode: 403,
    error: 'forbidden',
    action: 'upload',
    email: auth.email,
    role: auth.role,
    requestId: auth.requestId,
    requestedAt: auth.requestedAt,
    message: 'Недостаточно прав для загрузки документов.'
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
const payload = $json || {};
const stats = payload?.stats && typeof payload.stats === 'object' ? payload.stats : {};
const fragmentsCount = stats.total_fragments ?? stats.vectors_indexed ?? stats.indexed_chunks ?? stats.chunks ?? 0;
const avgChunkChars = stats.avg_chunk_chars ?? stats.average_chunk_chars ?? '';
const maxChunkChars = stats.max_chunk_chars ?? stats.chunk_max_chars ?? '';
const paragraphChunks = stats.paragraph_chunks ?? stats?.chunk_types?.paragraph ?? '';
const tableRowChunks = stats.table_row_chunks ?? stats?.chunk_types?.table_row ?? '';
const importantChunks = stats.important_chunks ?? stats?.chunk_types?.important ?? '';
const chunkMaxCharsSetting = stats.chunk_max_chars_setting ?? auth.maxChunkChars ?? '';
const collectionName = String(payload.collection_name || stats.collection || payload.collection || '').trim();
const processingMs = Math.max(0, Date.now() - Number(auth.requestStartedMs || Date.now()));
const message = String(payload?.message || payload?.detail || 'Upload processed').slice(0, 5000);
const status = payload?.ok === false ? 'failed' : 'success';
return [{
  json: {
    response: {
      ...payload,
      ok: payload?.ok === false ? false : true,
      authorizedEmail: auth.email,
      role: auth.role,
      requestId: auth.requestId,
      requestedAt: auth.requestedAt,
      processingMs
    },
    logRow: {
      created_at_utc: auth.requestedAt,
      request_id: auth.requestId,
      email: auth.email,
      role: auth.role,
      action: 'upload',
      original_file_name: auth.originalFileName || '',
      stored_doc_name: payload.doc_name || auth.originalFileName || '',
      doc_id: String(payload.doc_id || stats.doc_id || ''),
      file_size_bytes: String(auth.fileSizeBytes || 0),
      mime_type: auth.mimeType || '',
      file_sha1: auth.fileSha1 || '',
      status,
      chunks_count: String(fragmentsCount),
      avg_chunk_chars: String(avgChunkChars),
      max_chunk_chars: String(maxChunkChars),
      paragraph_chunks: String(paragraphChunks),
      table_row_chunks: String(tableRowChunks),
      important_chunks: String(importantChunks),
      chunk_max_chars_setting: String(chunkMaxCharsSetting),
      collection_name: collectionName,
      processing_ms: String(processingMs),
      message,
      execution_id: String($execution.id)
    }
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
return [{
  json: {
    ok: false,
    statusCode: 403,
    error: 'forbidden',
    action: 'collection_clear',
    email: auth.email,
    role: auth.role,
    requestId: auth.requestId,
    requestedAt: auth.requestedAt,
    message: 'Очистка коллекции разрешена только администратору.'
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
const payload = $json || {};
const processingMs = Math.max(0, Date.now() - Number(auth.requestStartedMs || Date.now()));
const message = String(payload?.message || 'Collection cleared').slice(0, 5000);
return [{
  json: {
    response: {
      ...payload,
      ok: true,
      statusCode: 200,
      authorizedEmail: auth.email,
      role: auth.role,
      requestId: auth.requestId,
      requestedAt: auth.requestedAt,
      processingMs
    },
    logRow: {
      created_at_utc: auth.requestedAt,
      request_id: auth.requestId,
      email: auth.email,
      role: auth.role,
      action: 'collection_clear',
      original_file_name: '',
      stored_doc_name: '',
      doc_id: '',
      file_size_bytes: '',
      mime_type: '',
      file_sha1: '',
      status: 'success',
      chunks_count: '0',
      avg_chunk_chars: '',
      max_chunk_chars: '',
      paragraph_chunks: '',
      table_row_chunks: '',
      important_chunks: '',
      chunk_max_chars_setting: '',
      collection_name: String(payload.collection_name || payload.name || ''),
      processing_ms: String(processingMs),
      message,
      execution_id: String($execution.id)
    }
  }
}];

const auth = $items('Resolve Authorization', 0, 0)?.json ?? $node['Resolve Authorization']?.json ?? {};
const normalizedFeedback = ['yes', 'true', '1'].includes(auth.feedbackValue) ? 'yes' : ['no', 'false', '0'].includes(auth.feedbackValue) ? 'no' : '';
if (!auth.targetRequestId || !normalizedFeedback) {
  return [{
    json: {
      response: {
        ok: false,
        statusCode: 400,
        error: 'invalid_feedback',
        action: 'feedback',
        requestId: auth.requestId,
        linkedRequestId: auth.targetRequestId || null,
        email: auth.email,
        role: auth.role,
        message: 'Для feedback нужны request_id и значение yes/no.'
      }
    }
  }];
}
const clickedAfterMsRaw = Number(auth.clickedAfterMs);
const clickedAfterMs = Number.isFinite(clickedAfterMsRaw) ? Math.max(0, Math.round(clickedAfterMsRaw)) : '';
return [{
  json: {
    response: {
      ok: true,
      statusCode: 200,
      action: 'feedback',
      requestId: auth.requestId,
      linkedRequestId: auth.targetRequestId,
      requestedAt: auth.requestedAt,
      email: auth.email,
      role: auth.role,
      savedFeedback: normalizedFeedback,
      message: 'Оценка полезности сохранена.'
    },
    logRow: {
      created_at_utc: auth.requestedAt,
      request_id: auth.targetRequestId,
      email: auth.email,
      role: auth.role,
      query_text: auth.query,
      answer_useful: normalizedFeedback,
      feedback_reason: String(auth.feedbackReason || '').slice(0, 1000),
      feedback_comment: String(auth.feedbackComment || '').slice(0, 2000),
      selected_doc: auth.selectedDoc || '',
      selected_citation: auth.selectedCitation || '',
      answer_text: String(auth.answerText || '').slice(0, 5000),
      clicked_after_ms: String(clickedAfterMs),
      execution_id: String($execution.id)
    }
  }
}];
